What does this program print?

```cpp
#include <iostream>
#include <string>
struct Patient { std::string name; };
struct Doctor {
    Patient* current{nullptr};
    void assign(Patient* p) { current = p; }
    void greet() {
        if (current)
            std::cout << "Treating " << current->name << "\n";
        else
            std::cout << "No patient\n";
    }
};
int main() {
    Patient p1{"Alice"}, p2{"Bob"};
    Doctor d;
    d.greet();
    d.assign(&p1);
    d.greet();
    d.assign(&p2);
    d.greet();
}
```

